def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        if ratio > 1.5:
            priorities[i] = float('inf')
            continue
        score = 0.0
        temp_ratio = ratio
        decay = 0.9
        factor = 1.0
        for j in range(7):
            if temp_ratio < 0.005:
                break
            base_val = np.log1p(temp_ratio) * np.sqrt(temp_ratio + 0.05)
            weight = 1.1 / (j + 2)
            increment = base_val * weight * factor
            score += increment
            temp_ratio *= decay
            factor *= 0.85
            if score > 8:
                break
        if score < 0.8:
            score *= 3
            if ratio < 0.4:
                for k in range(3):
                    score += (0.15 / (k + 1)) * (1 - temp_ratio)
        elif score < 3:
            score *= 9
            if capacity < item * 1.1:
                score += 4
            else:
                score -= 0.5
        else:
            if ratio > 0.9:
                score *= 14
            elif ratio > 0.6:
                score *= 9.5
            else:
                score *= 7
        if capacity < item * 0.85:
            score += 25
        elif capacity < item:
            score += 10
        if abs(capacity - round(capacity)) < 1e-5 and capacity > 1:
            score += 1.5
        priorities[i] = score
    finite = priorities[np.isfinite(priorities)]
    if finite.size == 0:
        return np.full_like(priorities, float('inf'))
    min_p = np.min(finite)
    max_p = np.max(finite)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = min_p * 200
        else:
            if priorities[i] == min_p:
                priorities[i] = 0
            elif priorities[i] == max_p:
                priorities[i] *= 2
            else:
                norm = (priorities[i] - min_p) / (max_p - min_p)
                priorities[i] = norm ** 1.5 * 15
    return priorities
